onClick:
{{
(() => {

  if (!InputEditName.text.trim()) {
    showAlert("Podaj imię i nazwisko.", "warning");
    return;
  }

  if (!InputEditMail.text.trim()) {
    showAlert("Podaj adres e-mail.", "warning");
    return;
  }

  if (!SelectEditRole.selectedOptionValue) {
    showAlert("Wybierz rolę.", "warning");
    return;
  }

  updateUser.run(
    () => {

      getUsers.run(
        () => {

          closeModal("ModalEdytujUzytkownika");

          resetWidget("InputEditName", true);
          resetWidget("InputEditMail", true);
          resetWidget("SelectEditRole", true);

          storeValue("editUser", null);

          showAlert(
            "Dane użytkownika zostały zaktualizowane.",
            "success"
          );

        },
        (error) => {

          showAlert(
            "Nie udało się odświeżyć listy użytkowników.",
            "warning"
          );

          console.error(error);

        }
      );

    },
    (error) => {

      const errorText = String(error);

      if (errorText.includes("users_mail_key")) {

        showAlert(
          "Użytkownik z podanym adresem e-mail już istnieje.",
          "warning"
        );

        return;
      }

      showAlert(
        "Błąd podczas aktualizacji użytkownika.",
        "error"
      );

      console.error(error);

    }
  );

})();
}}
